import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { createCaretVersionMap } from "./package-version-map.js";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..", "..");
const targetFile = path.join(repoRoot, "packages/create-litsx-app/src/published-package-versions.js");

const versionMap = createCaretVersionMap([
  "@litsx/compiler",
  "@litsx/core",
  "@litsx/eslint-plugin",
  "@litsx/typescript",
  "@litsx/vite-plugin",
  "prettier-plugin-litsx",
]);

const nextSource = [
  "// Generated by scripts/release/sync-scaffold-package-versions.js",
  `export const publishedPackageVersions = ${JSON.stringify(versionMap, null, 2)};`,
  "",
].join("\n");

fs.writeFileSync(targetFile, nextSource);
console.log("synced create-litsx-app published package versions");
